/* Test driver */
public class Main {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart("CA");
        cart.addItem(new Product("p1","Widget",100.00,"X"), 2);
        double sub = cart.getSubtotal();
        if (Math.abs(sub - 200.00) < 0.01) System.out.println("SUBTOTAL_OK");
        else System.out.println("SUBTOTAL_FAIL: " + sub);
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart("CA");
        cart.addItem(new Product("p1","Widget",100.00,"X"), 1);
        DiscountStrategy combo = new CompositeDiscount(
                new PercentageDiscount(10),
                new FlatDiscount(20.00));
        double d = combo.calculateDiscount(cart.getItems());
        if (Math.abs(d - 30.00) < 0.01) System.out.println("COMPOSITE_OK");
        else System.out.println("COMPOSITE_FAIL: " + d);
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ShoppingCart cart = new ShoppingCart("CA");
        cart.addItem(new Product("p1","Widget",100.00,"X"), 1);
        boolean ok = cart.applyCoupon(new Coupon("SAVE10", new FlatDiscount(10.00), 50.0));
        boolean bad = cart.applyCoupon(new Coupon("BIGMIN", new FlatDiscount(10.00), 500.0));
        if (ok && !bad) System.out.println("COUPON_OK");
        else System.out.println("COUPON_FAIL");
    }
}
